export const completeEnglishStudySession = async (
  englishSessionCompleteRequest: EnglishSessionCompleteRequest,
  options?: RequestInit,
): Promise<EnglishSessionCompleteResponse> => {
  return customFetch<EnglishSessionCompleteResponse>(
    getCompleteEnglishStudySessionUrl(),
    {
      ...options,
      method: "POST",
      headers: { "Content-Type": "application/json", ...options?.headers },
      body: JSON.stringify(englishSessionCompleteRequest),
    },
  );
};

export const getCompleteEnglishStudySessionMutationOptions = <
  TError = ErrorType<ValidationErrorResponse | UnauthorizedResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof completeEnglishStudySession>>,
    TError,
    { data: BodyType<EnglishSessionCompleteRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof completeEnglishStudySession>>,
  TError,
  { data: BodyType<EnglishSessionCompleteRequest> },
  TContext
> => {
  const mutationKey = ["completeEnglishStudySession"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof completeEnglishStudySession>>,
    { data: BodyType<EnglishSessionCompleteRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return completeEnglishStudySession(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

